/**
 * Generates public/firebase-messaging-sw.js from NEXT_PUBLIC_FIREBASE_* env vars.
 * The generated file is gitignored — never commit Firebase keys to the repo.
 */
import fs from "fs";
import path from "path";
import { fileURLToPath } from "url";

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const root = path.join(__dirname, "..");
const outFile = path.join(root, "public", "firebase-messaging-sw.js");

function loadEnvFile(filename) {
  const filePath = path.join(root, filename);
  if (!fs.existsSync(filePath)) return;
  const text = fs.readFileSync(filePath, "utf8");
  for (const line of text.split(/\r?\n/)) {
    const trimmed = line.trim();
    if (!trimmed || trimmed.startsWith("#")) continue;
    const eq = trimmed.indexOf("=");
    if (eq === -1) continue;
    const key = trimmed.slice(0, eq).trim();
    let value = trimmed.slice(eq + 1).trim();
    if (
      (value.startsWith('"') && value.endsWith('"')) ||
      (value.startsWith("'") && value.endsWith("'"))
    ) {
      value = value.slice(1, -1);
    }
    if (!process.env[key]) process.env[key] = value;
  }
}

loadEnvFile(".env");
loadEnvFile(".env.local");
loadEnvFile(".env.production");

const config = {
  apiKey: process.env.NEXT_PUBLIC_FIREBASE_API_KEY ?? "",
  authDomain: process.env.NEXT_PUBLIC_FIREBASE_AUTH_DOMAIN ?? "",
  projectId: process.env.NEXT_PUBLIC_FIREBASE_PROJECT_ID ?? "",
  storageBucket: process.env.NEXT_PUBLIC_FIREBASE_STORAGE_BUCKET ?? "",
  messagingSenderId: process.env.NEXT_PUBLIC_FIREBASE_MESSAGING_SENDER_ID ?? "",
  appId: process.env.NEXT_PUBLIC_FIREBASE_APP_ID ?? "",
};

const missing = Object.entries(config)
  .filter(([, value]) => !value)
  .map(([key]) => key);

if (missing.length > 0) {
  const stub = `// FCM service worker not generated — missing env: ${missing.join(", ")}
// Run: npm run generate:firebase-sw (after setting NEXT_PUBLIC_FIREBASE_* in .env.local)
self.addEventListener("push", () => {});
`;
  fs.writeFileSync(outFile, stub, "utf8");
  console.warn(`[firebase-sw] Stub written (missing: ${missing.join(", ")})`);
  process.exit(0);
}

const content = `/* eslint-disable no-undef */
// AUTO-GENERATED by scripts/generate-firebase-sw.mjs — do not edit or commit.
importScripts("https://www.gstatic.com/firebasejs/11.6.0/firebase-app-compat.js");
importScripts("https://www.gstatic.com/firebasejs/11.6.0/firebase-messaging-compat.js");

firebase.initializeApp(${JSON.stringify(config, null, 2)});

const messaging = firebase.messaging();

messaging.onBackgroundMessage((payload) => {
  const title = payload.notification?.title ?? "BISA Admin";
  const options = {
    body: payload.notification?.body ?? "",
    icon: "/images/logo/logo-icon.svg",
    data: payload.data ?? {},
  };
  self.registration.showNotification(title, options);
});
`;

fs.writeFileSync(outFile, content, "utf8");
console.log("[firebase-sw] Generated public/firebase-messaging-sw.js");
